1	export type Customer = {
2	  yearsWithMHPCO: number;
3	};
4	
5	export type Item = {
6	  type: string;
7	  material?: string;
8	  cursed?: boolean;
9	  enchantment?: number;
10	};
11	
12	export type QuoteStep = {
13	  op: "quote";
14	  items: Item[];
15	};
16	
17	export type Damage = {
18	  itemType: string;
19	  amount: number;
20	};
21	
22	export type Incident = {
23	  cause: string;
24	  damages: Damage[];
25	};
26	
27	export type ClaimStep = {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	};
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export type Scenario = {
36	  customer: Customer;
37	  steps: Step[];
38	};
39	
40	export type ClaimResult = {
41	  payout: number;
42	  remainingCap: number;
43	};
44	
45	export type Result = {
46	  premium?: number;
47	  payout?: number;
48	  remainingCap?: number;
49	};
50	
51	const PROCESSING_FEE = 5;
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
55	const HIGH_ENCHANTMENT_MINIMUM = 5;
56	const LOYALTY_DISCOUNT_RATE = 0.2;
57	const LOYALTY_MINIMUM_YEARS = 2;
58	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
59	
60	const BASE_PREMIUMS: Record<string, number> = {
61	  sword: 100,
62	  amulet: 60,
63	  staff: 80,
64	  potion: 40,
65	  rune: 25,
66	  moonstone: 25,
67	};
68	
69	const COMPONENT_BLOCK_SIZE = 3;
70	const COMPONENT_BLOCK_PREMIUM = 60;
71	
72	const countByType = (items: Item[]): Map<string, number> => {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
76	  }
77	  return counts;
78	};
79	
80	const groupBasePremium = (type: string, count: number): number =>
81	  count === COMPONENT_BLOCK_SIZE
82	    ? COMPONENT_BLOCK_PREMIUM
83	    : count * BASE_PREMIUMS[type];
84	
85	const computeBasePremium = (items: Item[]): number =>
86	  [...countByType(items)].reduce(
87	    (total, [type, count]) => total + groupBasePremium(type, count),
88	    0,
89	  );
90	
91	const sumBy = (items: Item[], amount: (item: Item) => number): number =>
92	  items.reduce((total, item) => total + amount(item), 0);
93	
94	const itemCurseSurcharge = (item: Item): number =>
95	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
96	
97	const itemHighEnchantmentSurcharge = (item: Item): number =>
98	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_MINIMUM
99	    ? BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
100	    : 0;
101	
102	const quotePremium = (
103	  customer: Customer,
104	  items: Item[],
105	  isFollowUp: boolean,
106	): number => {
107	  const basePremium = computeBasePremium(items);
108	  const curseSurcharge = sumBy(items, itemCurseSurcharge);
109	  const highEnchantmentSurcharge = sumBy(items, itemHighEnchantmentSurcharge);
110	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
111	  const loyaltyDiscount =
112	    customer.yearsWithMHPCO >= LOYALTY_MINIMUM_YEARS
113	      ? basePremium * LOYALTY_DISCOUNT_RATE
114	      : 0;
115	  const followUpDiscount = isFollowUp
116	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
117	    : 0;
118	  const exactPremium =
119	    basePremium +
120	    curseSurcharge +
121	    highEnchantmentSurcharge +
122	    firstInsuranceSurcharge -
123	    loyaltyDiscount -
124	    followUpDiscount +
125	    PROCESSING_FEE;
126	  return Math.ceil(exactPremium);
127	};
128	
129	const DEDUCTIBLE = 100;
130	const PAYOUT_CAP_MULTIPLIER = 2;
131	const HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT = 8;
132	const HALF_REIMBURSEMENT_RATE = 0.5;
133	
134	const INSURANCE_VALUES: Record<string, number> = {
135	  sword: 1000,
136	  rune: 250,
137	};
138	
139	const reimbursementFor = (insuredItem: Item, damage: Damage): number =>
140	  (insuredItem.enchantment ?? 0) >= HALF_REIMBURSEMENT_MINIMUM_ENCHANTMENT
141	    ? damage.amount * HALF_REIMBURSEMENT_RATE
142	    : damage.amount;
143	
144	const processClaim = (steps: Step[], claim: ClaimStep): ClaimResult => {
145	  const policy = steps[claim.policy] as QuoteStep;
146	  const insuranceSum = sumBy(policy.items, (item) => INSURANCE_VALUES[item.type]);
147	  const payoutCap = PAYOUT_CAP_MULTIPLIER * insuranceSum;
148	  const damage = claim.incident.damages[0];
149	  const insuredItem = policy.items.find(
150	    (item) => item.type === damage.itemType,
151	  ) as Item;
152	  const payout = reimbursementFor(insuredItem, damage) - DEDUCTIBLE;
153	  return { payout, remainingCap: payoutCap - payout };
154	};
155	
156	export const processScenario = (scenario: Scenario): { results: Result[] } => ({
157	  results: scenario.steps.map((step, index) =>
158	    step.op === "quote"
159	      ? { premium: quotePremium(scenario.customer, step.items, index > 0) }
160	      : processClaim(scenario.steps, step),
161	  ),
162	});
